"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["97055"],{60673(t){t.exports=JSON.parse('{"tag":{"label":"logistics","permalink":"/sysanalyst-kb.github.io/tech/tags/logistics","allTagsPath":"/sysanalyst-kb.github.io/tech/tags","count":4,"items":[{"id":"edi","title":"EDI \u2014 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u044B\u0439 \u043E\u0431\u043C\u0435\u043D \u0434\u0430\u043D\u043D\u044B\u043C\u0438","description":"EDI (Electronic Data Interchange) \u2014 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0433\u043E \u043E\u0431\u043C\u0435\u043D\u0430 \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u043C\u0438 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u0430\u043C\u0438 \u043C\u0435\u0436\u0434\u0443 \u0443\u0447\u0430\u0441\u0442\u043D\u0438\u043A\u0430\u043C\u0438 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0446\u0435\u043F\u043E\u0447\u043A\u0438 (\u043F\u043E\u0441\u0442\u0430\u0432\u0449\u0438\u043A \u2194 \u0440\u0438\u0442\u0435\u0439\u043B\u0435\u0440 \u2194 \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u0447\u0438\u043A \u2194 \u043C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441). \u0412 \u0420\u0424 EDI-\u043E\u0431\u043E\u0440\u043E\u0442 \u0440\u0435\u0430\u043B\u0438\u0437\u0443\u0435\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 \u043F\u0440\u043E\u0432\u0430\u0439\u0434\u0435\u0440\u043E\u0432 (\u0414\u0438\u0430\u0434\u043E\u043A, \u0421\u0411\u0418\u0421, 1\u0421-\u042D\u0414\u041E, \u041A\u043E\u0440\u0443\u0441) \u0438 \u0444\u043E\u0440\u043C\u0430\u0442\u044B ORDERS (\u0437\u0430\u043A\u0430\u0437 \u043D\u0430 \u043F\u043E\u0441\u0442\u0430\u0432\u043A\u0443), DESADV (\u0443\u0432\u0435\u0434\u043E\u043C\u043B\u0435\u043D\u0438\u0435 \u043E\u0431 \u043E\u0442\u0433\u0440\u0443\u0437\u043A\u0435), RECADV (\u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u0435 \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F), INVOIC (\u0441\u0447\u0451\u0442-\u0444\u0430\u043A\u0442\u0443\u0440\u0430). EDI \u0441\u043D\u0438\u0436\u0430\u0435\u0442 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0438\u0437\u0434\u0435\u0440\u0436\u043A\u0438 \u043D\u0430 30-50% \u043F\u043E \u0441\u0440\u0430\u0432\u043D\u0435\u043D\u0438\u044E \u0441 \u0431\u0443\u043C\u0430\u0436\u043D\u044B\u043C \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u043E\u0431\u043E\u0440\u043E\u0442\u043E\u043C. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u0446\u0438\u0440\u0443\u0435\u0442 \u043A\u0430\u0440\u0442\u044B \u0442\u0440\u0430\u043D\u0441\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 (mapping) \u043C\u0435\u0436\u0434\u0443 \u0444\u043E\u0440\u043C\u0430\u0442\u0430\u043C\u0438 \u0438 \u043D\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442 \u0441\u0442\u0430\u0442\u0443\u0441\u043D\u0443\u044E \u043C\u043E\u0434\u0435\u043B\u044C \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u0432.","permalink":"/sysanalyst-kb.github.io/tech/edi"},{"id":"tms","title":"TMS \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u043A\u0430\u043C\u0438","description":"TMS (Transportation Management System) \u2014 \u043A\u043B\u0430\u0441\u0441 \u0441\u0438\u0441\u0442\u0435\u043C \u0434\u043B\u044F \u043F\u043B\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0438 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044F \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442\u0438\u0440\u043E\u0432\u043A\u0438 \u0433\u0440\u0443\u0437\u043E\u0432. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u0432\u0435\u043D\u0434\u043E\u0440\u044BTMS (\u0420\u0424), SAP TM (enterprise), Oracle OTM, Solomon TMS (SaaS, \u0440\u0438\u0442\u0435\u0439\u043B), RetaiLite. TMS \u0440\u0435\u0448\u0430\u0435\u0442 \u0437\u0430\u0434\u0430\u0447\u0438: \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0430\u0446\u0438\u044F, \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u0447\u0438\u043A\u0430\u043C\u0438, \u0442\u0430\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F, \u0442\u0440\u0435\u043A\u0438\u043D\u0433, \u042D\u0414\u041E, \u0432\u0437\u0430\u0438\u043C\u043E\u0440\u0430\u0441\u0447\u0451\u0442\u044B. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043D\u0430 \u043F\u0440\u043E\u0435\u043A\u0442\u0435 TMS \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u0431\u0438\u0437\u043D\u0435\u0441-\u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u043E\u043A, \u043D\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442 \u0442\u0430\u0440\u0438\u0444\u043D\u044B\u0435 \u0441\u0445\u0435\u043C\u044B, \u0438\u043D\u0442\u0435\u0433\u0440\u0438\u0440\u0443\u0435\u0442 TMS \u0441 WMS/ERP \u0438 \u043F\u0440\u043E\u0432\u0430\u0439\u0434\u0435\u0440\u0430\u043C\u0438 \u042D\u0414\u041E.","permalink":"/sysanalyst-kb.github.io/tech/tms"},{"id":"wms","title":"WMS \u2014 \u0441\u043A\u043B\u0430\u0434\u0441\u043A\u0438\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B","description":"WMS (Warehouse Management System) \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0441\u043A\u043B\u0430\u0434\u043E\u043C SAP EWM, Oracle WMS, Manhattan, 1\u0421:WMS.","permalink":"/sysanalyst-kb.github.io/tech/wms"},{"id":"geodata","title":"\u0413\u0435\u043E\u0434\u0430\u043D\u043D\u044B\u0435 \u2014 \u043A\u0430\u0440\u0442\u044B, \u0433\u0435\u043E\u043A\u043E\u0434\u0438\u043D\u0433, \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0430\u0446\u0438\u044F","description":"\u0413\u0435\u043E\u0434\u0430\u043D\u043D\u044B\u0435 \u2014 \u0444\u0443\u043D\u0434\u0430\u043C\u0435\u043D\u0442 \u043B\u043E\u0433\u0438\u0441\u0442\u0438\u043A\u0438 \u042F\u043D\u0434\u0435\u043A\u0441.\u041A\u0430\u0440\u0442\u044B (API \u0413\u0435\u043E\u043A\u043E\u0434\u0435\u0440, \u041C\u0430\u0440\u0448\u0440\u0443\u0442\u044B), 2GIS (\u0441\u043F\u0440\u0430\u0432\u043E\u0447\u043D\u0438\u043A \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0439), OpenStreetMap (\u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0435 \u0434\u0430\u043D\u043D\u044B\u0435), Mapbox (\u043A\u0430\u0441\u0442\u043E\u043C\u0438\u0437\u0430\u0446\u0438\u044F \u043A\u0430\u0440\u0442), Google Maps (\u0433\u043B\u043E\u0431\u0430\u043B\u044C\u043D\u043E\u0435 \u043F\u043E\u043A\u0440\u044B\u0442\u0438\u0435). \u0417\u0430\u0434\u0430\u0447\u0438 \u0441 \u0433\u0435\u043E\u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u0442\u043E\u0447\u043D\u043E\u0441\u0442\u044C \u0433\u0435\u043E\u043A\u043E\u0434\u0438\u043D\u0433\u0430 (\u0443\u0440\u043E\u0432\u0435\u043D\u044C \u0434\u043E\u043C\u0430/\u0443\u043B\u0438\u0446\u044B), \u0444\u043E\u0440\u043C\u0430\u0442 \u043A\u043E\u043E\u0440\u0434\u0438\u043D\u0430\u0442 (WGS-84), \u0447\u0430\u0441\u0442\u043E\u0442\u0443 \u043E\u0431\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u044F \u043F\u0440\u043E\u0431\u043E\u043A (1-5 \u043C\u0438\u043D), \u043F\u043E\u043A\u0440\u044B\u0442\u0438\u0435 \u0440\u0435\u0433\u0438\u043E\u043D\u043E\u0432.","permalink":"/sysanalyst-kb.github.io/tech/geodata"}],"unlisted":false}}')}}]);